#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

#ifndef blockdim
#define blockdim 1
#endif

#define TOTAL_ELEMENTS_PER_WI (ELEMENTS_PER_THREAD * FUSION_DEGREE)

__kernel void benchmark_func(class_T seed, __global class_T* c) {
  (void)seed;

  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);
  const size_t lid = get_local_id(0);
  const size_t group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const size_t stride = (size_t)blockdim;
  const size_t base = group * ((size_t)TOTAL_ELEMENTS_PER_WI * stride) + lid;
#else
  const size_t stride = gsize;
  const size_t base = gid;
#endif

  class_T sum = (class_T)(0);

  for (uint fusion = 0; fusion < (uint)FUSION_DEGREE; ++fusion) {
    const size_t fusion_base = base + (size_t)fusion * (size_t)ELEMENTS_PER_THREAD * stride;

    class_T f[8];
    for (uint k = 0; k < 8; ++k) {
      f[k] = c[fusion_base + (size_t)k * stride];
    }

    for (uint i = 0; i < (uint)ELEMENTS_PER_THREAD; ++i) {
      const size_t idx = fusion_base + (size_t)i * stride;
      const class_T v = c[idx];

      class_T t0 = v;
      class_T t1 = v;
      class_T t2 = v;
      class_T t3 = v;
      class_T t4 = v;
      class_T t5 = v;
      class_T t6 = v;
      class_T t7 = v;

      for (uint j = 0; j < (uint)(COMPUTE_ITERATIONS / 8); ++j) {
        t0 = t0 * t0 + f[0];
        t1 = t1 * t1 + f[1];
        t2 = t2 * t2 + f[2];
        t3 = t3 * t3 + f[3];
        t4 = t4 * t4 + f[4];
        t5 = t5 * t5 + f[5];
        t6 = t6 * t6 + f[6];
        t7 = t7 * t7 + f[7];
      }

#if (COMPUTE_ITERATIONS % 8) > 0
      t0 = t0 * t0 + f[0];
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
      t1 = t1 * t1 + f[1];
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
      t2 = t2 * t2 + f[2];
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
      t3 = t3 * t3 + f[3];
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
      t4 = t4 * t4 + f[4];
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
      t5 = t5 * t5 + f[5];
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
      t6 = t6 * t6 + f[6];
#endif

      sum += t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
    }
  }

  c[base] = sum;
}
